import{_ as t,o as a,c as e,a1 as r}from"./chunks/framework.CqNg6vjd.js";const u=JSON.parse('{"title":"连点成线","description":"","frontmatter":{"title":"连点成线","customTag":"blog>个人思考","editLink":true,"date":"2025.09.20"},"headers":[],"relativePath":"blog/connect-dot.md","filePath":"blog/connect-dot.md","lastUpdated":1772804009000}'),n={name:"blog/connect-dot.md"};function o(s,p,i,g,l,h){return a(),e("div",null,[...p[0]||(p[0]=[r('<h1 id="连点成线" tabindex="-1">“连点成线” <a class="header-anchor" href="#连点成线" aria-label="Permalink to &quot;“连点成线”&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>Notion 是我很喜欢的一款应用，</p><p>因为其丰富能力、交互体验、产品哲学，</p><p>我觉得它是有价值观的工艺品。</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112632.png" alt="image.png"></p><p>一直想找个机会写写 Notion,</p><p>具体如，</p><ul><li>产品用法：聊聊其文档、多维表格的用法，</li><li>交互体验：讨论其优雅的交互体验，</li><li>产品哲学：阐述我对其产品哲学的理解，“软件界的乐高”，</li><li>知识管理：探索其与“知识管理”的工具，</li></ul><p>还有其他…</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112642.png" alt="image.png"></p><p>有这个想法很久了，</p><p>但我迟迟没有动笔，</p><p>因为有些命题，</p><p>可能我自己没想清楚，</p><p>又或许是，</p><p>我不确定我是否能表达清楚。</p><p>但近期 Notion 发布 Agent 的模式，</p><p>我试用体验后，</p><p>有些超出我的预期。</p><p>也希望和你分享下，</p><p>并且记录下我个人的一点想法。</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112653.png" alt="image.png"></p><h2 id="使用体验" tabindex="-1">使用体验 <a class="header-anchor" href="#使用体验" aria-label="Permalink to &quot;使用体验&quot;">​</a></h2><p>由于本文主要聚焦的是 Notion Agent 相关，</p><p>所以 Notion 其他能力不会在这里描述，</p><p>但后续也许我会再写文章介绍介绍。</p><h3 id="日程梳理" tabindex="-1">日程梳理 <a class="header-anchor" href="#日程梳理" aria-label="Permalink to &quot;日程梳理&quot;">​</a></h3><p>本人日常 Notion 日历管理日程，</p><p>如下图所示，是我五天的日程安排。</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112702.png" alt="image.png"></p><p>但此前一直希望有个能力是，</p><p>“能够总结我一周的时间分配，做分析并给出建议”。</p><p>而当 Notion Agent 的发布之后，</p><p>我也尝试了这个场景，</p><p>效果如下。</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112719.png" alt="image.png"></p><p>实际上，是有点超出预期的。</p><ul><li><strong>时间统计</strong>：可以通过简便的方式，提供你的时间分布情况，了解具体的数据。</li><li><strong>外界输入</strong>：基于上方的数据， AI 可以提供给你建议，并且你可以谈论完善这个建议。</li></ul><h3 id="读过-听过" tabindex="-1">读过/听过 <a class="header-anchor" href="#读过-听过" aria-label="Permalink to &quot;读过/听过&quot;">​</a></h3><p>阅读书籍，听播客已经是我的日常，</p><p>也可以看作是我进行内容输入的方式。</p><p>我个人十分注重内容的输入，</p><p>也察觉到自己阅读的类别在发生变化，</p><p>如近几年会看哲学，人文社科等内容。</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112734.png" alt="image.png"></p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112746.png" alt="image.png"></p><p>但我希望也有外部提供的视角反馈，</p><p>于是，我也试着问了这两个问题。</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112757.png" alt="image.png"><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112805.png" alt="image.png"></p><p>我无法描述当时看到结果的感觉，</p><p>但总体来说有些欣慰吧。</p><h3 id="写过的痕迹" tabindex="-1">写过的痕迹 <a class="header-anchor" href="#写过的痕迹" aria-label="Permalink to &quot;写过的痕迹&quot;">​</a></h3><p>从 2023 年开始，</p><p>个人就在间歇地进行写作，</p><p>在 Notion 上也积累了不少自己的博客。</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112819.png" alt="image.png"></p><p>这几年过程中，</p><p>写作的风格在不断地变化，</p><p>而这些大概是因为个人变化所引起。</p><p>我希望它能够根据我写作风格的变化，</p><p>从而来分析/推导出我个人的变化。</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112838.png" alt="image.png"></p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112846.png" alt="image.png"></p><p>结果出来的时候，</p><p>我心中有些触动。</p><p>但并非因为它的回复很准确，</p><p>恰恰相反，</p><p>我认为这只是外界的一种反馈，</p><p>虽然有一定相似度，但难免存在偏差。</p><p>而我被触动的是，</p><p>有一种“被记住”的感觉。</p><h3 id="课题学习" tabindex="-1">课题学习 <a class="header-anchor" href="#课题学习" aria-label="Permalink to &quot;课题学习&quot;">​</a></h3><p>Notion 的一个使用场景，</p><p>就是知识学习和管理了。</p><p>而此前 Notion 更多由于组织知识内容，</p><p>但并没有集成过多获取外部知识的能力，</p><p>以至于，</p><p>很多时候需要从外部系统手动复制到 notion 中。</p><p>但这次的 Notion Agent 的能力，</p><p>则塑造了一个方便内外部信息的组织信息环境。</p><p>如果你要学习一个话题，如 <code>Context Engineering</code></p><p>那么 Notion Agent 应该是能够给你信息输入，并且可以有具体动作。</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112907.png" alt="image.png"></p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112914.png" alt="image.png"></p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112922.png" alt="image.png"></p><p>同时，这些内容不是一次性消费品，</p><p>你可以不断修改，迭代这些内容。</p><p>Notion 的想象空间还很大，</p><p>我这里只是列举了一部分使用场景，</p><p>但这些例子，</p><p>已经将我过去所积累的知识和行动，</p><p>渐渐地串起来，连点成线。</p><h2 id="一点思考" tabindex="-1">一点思考 <a class="header-anchor" href="#一点思考" aria-label="Permalink to &quot;一点思考&quot;">​</a></h2><p>前文主要探讨了具体使用场景，</p><p>但我还想试图挖掘背后的东西</p><p>虽然有些想法不一定对，</p><p>但我还是希望分享出来。</p><h3 id="外界反馈" tabindex="-1">外界反馈 <a class="header-anchor" href="#外界反馈" aria-label="Permalink to &quot;外界反馈&quot;">​</a></h3><p>当你形成了一个习惯，</p><p>将自己的想法、计划、文章、记录等写入 Notion 中后，</p><p>实际上， Notion 是可以结合这些内容给你反馈的。</p><p>具几个场景</p><ul><li>阅读/播客：可以总结你接收的内容信息，从而做总结。</li><li>文章内容：可以根据你写的文章内容想法，从而分析。</li><li>记账软件：根据你的消费情况，从而给出你一些建议</li><li>时间管理：根据你的时间分配，以及你开始的计划，从而给出数据和反馈。</li></ul><p>下方是 Notion 对我近几年写作风格的总结</p><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112948.png" alt="image.png"></p><p><strong>而接受外部的反馈，也许可以不断纠偏。</strong></p><h3 id="组织信息的环境" tabindex="-1">组织信息的环境 <a class="header-anchor" href="#组织信息的环境" aria-label="Permalink to &quot;组织信息的环境&quot;">​</a></h3><p>Notion 这次给我的另外的惊喜点，</p><p>是他加强了组织信息的环境。</p><p>如现在你可以通过 Notion 获取外部的信息</p><ul><li>Research: 可以通过联网等能力查询外部信息。</li><li>第三方工具： Notion 支持将第三方软件等信息集成进来。</li><li>DataBase: 通过 DataBase 你可以写入结构化数据。</li></ul><p><img src="https://raw.githubusercontent.com/hua-bang/assert-store/master/20250920112956.png" alt="image.png"></p><p>叠加 Notion 的信息组织能力，</p><p>塑造了 “信息获取 → 信息关联/组织 → 信息输出”的环境。</p><p><strong>一个好的信息环境，</strong></p><p><strong>从而能激发更多的想法和内容。</strong></p><h3 id="连点成线-1" tabindex="-1">“连点成线” <a class="header-anchor" href="#连点成线-1" aria-label="Permalink to &quot;“连点成线”&quot;">​</a></h3><p>在我早期用 Notion 的时候，</p><p>实际上，</p><p>做了很多“日程/读书/播客”的记录，</p><p>做了不少不同话题的知识分类。</p><p>但实际上，</p><p>当时更多是给我自己做检索使用，</p><p>这些数据实际上并没有那么灵活关联。</p><p>而随着这两年 AI 的发展，</p><p>这些数据更容易进行关联了。</p><ul><li><strong>非结构化数据流动</strong>：大模型可以方便处理非结构化数据，流动传递效率更高。</li><li><strong>不同数据类型的桥接</strong>：不同的数据类型的桥接，可以变得成本更低。</li></ul><p>而这些会便于，</p><p>过去和现在的数据比较，</p><p>不同类别的知识做关联，</p><p>将一个个点串起来，</p><p>从而有更宏观的视角。</p><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>本文花了很大篇幅在讲 Notion 的功能，</p><p>但我想说的是，</p><p>我们关注点可以不仅仅在工具上，</p><p>也可以留意背后的逻辑方法，</p><p>甚至探索其产品哲学和价值观。</p><p><strong>你会发现，</strong></p><p><strong>从工具本体到产品哲学和价值观，</strong></p><p><strong>也是一个知识“连点成线”的过程。</strong></p>',142)])])}const m=t(n,[["render",o]]);export{u as __pageData,m as default};
